import SweetAlertContext from './SweetAlertContextContext'
import React,{useState} from 'react'
import "./styles.css";
import Swal from "sweetalert2";


function SweetAlertState(props) {
    const successAlert = async () => {
        Swal.fire({
          title: "Good job!",
          text: "You clicked the button",
          icon: "success"
        });
        // or Swal.fire( 'Good job!','You clicked the button','success');
      };
      const questionAlert = () => {
        Swal.fire({  
            title: 'Do you have a problem to solve?!',  
            text: 'Ask us on dirask',
            icon: 'question'
          }); 
    }
    return (
        <SweetAlertContext.Provider value={{successAlert,questionAlert}}>
            {props.children};
        </SweetAlertContext.Provider>
    )
}

export default SweetAlertState
